// Extraer propiedades de la respuesta del scraper
const response = $input.first().json;
const webhookData = $('Webhook Trigger (Desde GHL)').item.json || {};
const webhookBody = webhookData.body || {};
const callContactId = webhookData.contactId || webhookBody.contactId || (webhookData.contactIds && webhookData.contactIds[0]) || '';

if (!response.success || !response.data || !response.data.properties || response.data.properties.length === 0) {
  return [{
    json: {
      hasResults: false,
      contactId: callContactId,
      whatsappMessage: 'Hola, recién terminé de escanear el mercado entero y por el momento no encontré opciones que coincidan 100% con tu pedido. 😔 Seguiré en contacto si ingresa algo nuevo.'
    }
  }];
}

const properties = response.data.properties;

// Armar un resumen corto. GHL permite mensajes que no sean demasiado inmensos.
let resumenPropiedades = '';
for (let i = 0; i < Math.min(3, properties.length); i++) {
  resumenPropiedades += `\n🔹 *${properties[i].title}*\n💰 ${properties[i].price}\n📍 ${properties[i].location}\n🔗 Ver Ficha: ${properties[i].rebrandedUrl}\n`;
}

// El enlace general para ver todo el listado, podemos armarlo en base a los datos:
// ej. "https://catalogo.korvance.com/busqueda?barrio=palermo&operacion=venta..."
// Pero el scraper ya devuelve el enlace real original. 
// Si creaste un enlace en tu API (ej: response.data.searchUrl), puedes usarlo aquí.
const urlListadoDinamico = `https://catalogo.korvance.com/busqueda?operacion=${webhookBody.operacion || 'venta'}&tipo=${webhookBody.tipo || 'departamentos'}&barrio=${webhookBody.barrio || 'palermo'}&ambientes=${webhookBody.ambientes || ''}`;

// Crear mensaje final de WhatsApp
const finalMessage = `¡Hola! Estuve escaneando el mercado y *encontré ${properties.length} opciones* interesantes con esos filtros.\n\nTe dejo mis destacadas:${resumenPropiedades}\n\n👉 *[Ver todo el listado completo aquí]*\n${urlListadoDinamico}\n\n¿Te gustaría coordinar una visita para alguna de ellas?`;

// Devolver la info estructurada
return [{
  json: {
    hasResults: true,
    contactId: callContactId,
    whatsappMessage: finalMessage,
    totalProperties: properties.length,
    listUrl: urlListadoDinamico
  }
}];
